import { FunctionComponent } from 'preact';
import { Button, Modal, ProgressSpinner } from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { PaymentCard } from '@/account/components/PaymentCard';
import { PaymentModalProps } from '@/account/types';
import '@/account/components/PaymentModal/PaymentModal.css';

export const PaymentModal: FunctionComponent<PaymentModalProps> = ({
  open,
  submitLoading,
  onRemoveToken,
  closeModal,
  cardBrand,
  lastFourDigits,
  expired,
  variant,
  minifiedView,
}) => {
  const translations = useText({
    title: 'Account.Payments.removePaymentModal.title',
    description: 'Account.Payments.removePaymentModal.description',
    actionCancel: 'Account.Payments.removePaymentModal.actionCancel',
    actionConfirm: 'Account.Payments.removePaymentModal.actionConfirm',
  });

  if (!open) return null;

  return (
    <Modal
      className="account-payment-modal--overlay"
      title={<h3>{translations.title}</h3>}
      size="full"
      data-testid="paymentModal"
      showCloseButton
      onClose={closeModal}
    >
      <div className="account-payment-modal">
        {submitLoading ? (
          <div
            className="account-payment-modal__spinner"
            data-testid="progressSpinner"
          >
            <ProgressSpinner stroke={'4'} size={'large'} />
          </div>
        ) : null}
        <p>{translations.description}</p>
        {cardBrand && lastFourDigits ? (
          <PaymentCard
            cardBrand={cardBrand}
            lastFourDigits={lastFourDigits}
            expired={expired}
            variant={variant}
            minifiedView={minifiedView}
          />
        ) : null}
        <div className="account-payment-modal__buttons">
          <Button
            // @ts-ignore
            type={'button'}
            onClick={closeModal}
            variant="secondary"
            disabled={submitLoading}
          >
            {translations.actionCancel}
          </Button>
          <Button disabled={submitLoading} onClick={onRemoveToken}>
            {translations.actionConfirm}
          </Button>
        </div>
      </div>
    </Modal>
  );
};
