import { FunctionComponent } from 'preact';
import { useCallback, useId } from 'preact/compat';
import { classes } from '@adobe-commerce/elsie/lib';
import { Card, Button, Tag } from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { PaymentCardProps } from '@/account/types';
import '@/account/components/PaymentCard/PaymentCard.css';

export const PaymentCard: FunctionComponent<PaymentCardProps> = ({
  cardBrand,
  lastFourDigits,
  expired = false,
  onRemove,
  variant = 'secondary',
  minifiedView = false,
}) => {
  const paymentCardAriaId = useId();

  const translations = useText({
    actionRemove: 'Account.Payments.paymentCard.actionRemove',
    cardEndingIn: 'Account.Payments.paymentCard.cardEndingIn',
    expiredLabel: 'Account.Payments.paymentCard.expiredLabel',
  });

  const handleRemove = useCallback(() => {
    onRemove?.();
  }, [onRemove]);

  const maskedNumber = `•••• ${lastFourDigits}`;
  const cardDescription = `${translations.cardEndingIn} ${maskedNumber}`;

  return (
    <Card
      variant={variant}
      className={classes([
        'account-payment-card',
        minifiedView && 'account-payment-card--minified',
      ])}
      data-testid="paymentCard"
    >
      <div className="account-payment-card__action">
        {onRemove ? (
          <Button
            // @ts-ignore
            type="button"
            variant="tertiary"
            onClick={handleRemove}
            data-testid="removeButton"
            aria-label={`${translations.actionRemove} ${cardBrand} ${cardDescription}`}
            aria-describedby={paymentCardAriaId}
          >
            {translations.actionRemove}
          </Button>
        ) : null}
      </div>
      <div className="account-payment-card__description" id={paymentCardAriaId}>
        <p className="account-payment-card__card-brand" data-testid="cardBrand">
          {cardBrand}
        </p>
        <p
          className="account-payment-card__card-number"
          data-testid="cardNumber"
        >
          {cardDescription}
        </p>
      </div>
      {expired ? (
        <div className="account-payment-card__labels" data-testid="expiredTag">
          <Tag
            label={(translations.expiredLabel ?? 'Expired').toLocaleUpperCase()}
          />
        </div>
      ) : null}
    </Card>
  );
};
