import { FunctionComponent } from 'preact';
import {
  Table,
  Skeleton,
  SkeletonRow,
  Pagination,
  IllustratedMessage,
  Card,
} from '@adobe-commerce/elsie/components';
import { classes } from '@adobe-commerce/elsie/lib';
import { SellerAssistedBuyingActivityTableProps } from '@/account/types';
import '@/account/components/SellerAssistedBuyingActivityTable/SellerAssistedBuyingActivityTable.css';

export const SellerAssistedBuyingActivityTable: FunctionComponent<
  SellerAssistedBuyingActivityTableProps
> = ({
  loading,
  adminAssistanceActions,
  tableHeaders,
  actionTypesMap,
  emptyStateMessage,
  featureDisabledMessage,
  isRemoteShoppingAssistanceAvailable = true,
  errorMessage,
  currentPage,
  onPageChange,
  withWrapper = true,
}) => {
  if (loading) {
    return (
      <Skeleton>
        <SkeletonRow variant="row" fullWidth={true} />
        <SkeletonRow variant="row" fullWidth={true} />
        <SkeletonRow variant="row" fullWidth={true} />
      </Skeleton>
    );
  }

  if (!isRemoteShoppingAssistanceAvailable) {
    return (
      <div className="account-seller-assisted-buying-activity-table__alert">
        <IllustratedMessage heading={featureDisabledMessage} />
      </div>
    );
  }

  if (errorMessage) {
    return (
      <div className="account-seller-assisted-buying-activity-table__error">
        <IllustratedMessage heading={errorMessage} />
      </div>
    );
  }

  if (!adminAssistanceActions?.items?.length) {
    return (
      <div className="account-seller-assisted-buying-activity-table__empty">
        <IllustratedMessage heading={emptyStateMessage} />
      </div>
    );
  }

  const columns = [
    {
      label: tableHeaders.action,
      key: 'action',
      ariaLabel: tableHeaders.action,
    },
    { label: tableHeaders.date, key: 'date', ariaLabel: tableHeaders.date },
    {
      label: tableHeaders.details,
      key: 'details',
      ariaLabel: tableHeaders.details,
    },
  ];

  const rowData = adminAssistanceActions.items.map((item) => ({
    action: actionTypesMap[item.action] || item.action,
    date: item.date,
    details: item.details,
  }));

  const totalPages = adminAssistanceActions.pageInfo.totalPages;
  const showPagination = totalPages > 1;
  const table = (
    <div className="account-seller-assisted-buying-activity-table">
      <div className="account-seller-assisted-buying-activity-table__table-wrapper">
        <Table
          columns={columns}
          rowData={rowData}
          mobileLayout="stacked"
          className="account-seller-assisted-buying-activity-table__table"
        />
      </div>
    </div>
  );

  return (
    <>
      {withWrapper ? (
        <Card
          variant="secondary"
          className={classes([
            'account-seller-assisted-buying-activity-table-card',
          ])}
        >
          {table}
        </Card>
      ) : (
        table
      )}
      {showPagination && (
        <div className="account-seller-assisted-buying-activity-table__pagination">
          <Pagination
            currentPage={currentPage}
            totalPages={totalPages}
            onChange={onPageChange}
          />
        </div>
      )}
    </>
  );
};
