import { getStoreConfig } from '@/account/api';
import { StoreConfigModel } from '@/account/data/models';
import { useEffect, useState } from 'preact/hooks';

const getCachedStoreConfig = (): StoreConfigModel | null => {
  const storeConfigString = sessionStorage.getItem('accountStoreConfig');

  if (!storeConfigString) return null;

  try {
    return JSON.parse(storeConfigString);
  } catch (error) {
    console.error('Failed to parse cached store config:', error);
    sessionStorage.removeItem('accountStoreConfig');
    return null;
  }
};

export const useGetStoreConfigs = () => {
  const [loading, setLoading] = useState<boolean>(true);
  const [passwordConfigs, setPasswordConfigs] = useState<{
    minLength: number;
    requiredCharacterClasses: number;
  } | null>(null);
  const [remoteShoppingAssistanceConfigs, setRemoteShoppingAssistanceConfigs] =
    useState<{
      shoppingAssistanceEnabled: boolean;
      shoppingAssistanceCheckboxTitle: string;
      shoppingAssistanceCheckboxTooltip: string;
    } | null>(null);

  const applyStoreConfig = (config: StoreConfigModel) => {
    const {
      minLength,
      requiredCharacterClasses,
      shoppingAssistanceEnabled,
      shoppingAssistanceCheckboxTitle,
      shoppingAssistanceCheckboxTooltip,
    } = config;

    setPasswordConfigs({
      minLength,
      requiredCharacterClasses,
    });

    setRemoteShoppingAssistanceConfigs({
      shoppingAssistanceEnabled,
      shoppingAssistanceCheckboxTitle,
      shoppingAssistanceCheckboxTooltip,
    });
  };

  useEffect(() => {
    const cachedStoreConfig = getCachedStoreConfig();

    if (cachedStoreConfig) {
      applyStoreConfig(cachedStoreConfig);
      setLoading(false);
      return;
    }

    getStoreConfig()
      .then((response) => {
        if (!response) return;

        sessionStorage.setItem('accountStoreConfig', JSON.stringify(response));
        applyStoreConfig(response);
      })
      .catch((error) => {
        console.error('Failed to load store config:', error);
      })
      .finally(() => {
        setLoading(false);
      });
  }, []);

  return { loading, passwordConfigs, remoteShoppingAssistanceConfigs };
};
