import { FunctionComponent, JSX } from 'preact';
import { useState } from 'preact/hooks';
import {
  Checkbox,
  Field,
  IllustratedMessage,
  InLineAlert,
  Skeleton,
  SkeletonRow,
} from '@adobe-commerce/elsie/components';
import { SellerAssistedBuyingSettingsControlProps } from '@/account/types';
import '@/account/components/SellerAssistedBuyingSettingsControl/SellerAssistedBuyingSettingsControl.css';

export const SellerAssistedBuyingSettingsControl: FunctionComponent<
  SellerAssistedBuyingSettingsControlProps
> = ({
  loading,
  isRemoteShoppingAssistanceAvailable,
  isRemoteShoppingAssistanceEnabled,
  showAlert,
  checkboxLabel,
  checkboxTooltip,
  alertMessage,
  featureDisabledMessage,
  handleCheckboxChange,
  handleDismissAlert,
}) => {
  const [showTooltip, setShowTooltip] = useState(false);

  if (loading) {
    return (
      <Skeleton>
        <SkeletonRow variant="row" />
      </Skeleton>
    );
  }

  if (!loading && !isRemoteShoppingAssistanceAvailable) {
    return (
      <div className="account-seller-assisted-buying-settings-control__alert">
        <IllustratedMessage heading={featureDisabledMessage} />
      </div>
    );
  }

  return (
    <div className="account-seller-assisted-buying-settings-control">
      {!isRemoteShoppingAssistanceEnabled && showAlert && (
        <div className="account-seller-assisted-buying-settings-control__alert">
          <InLineAlert
            variant="secondary"
            type="warning"
            heading={alertMessage}
            onDismiss={handleDismissAlert}
          />
        </div>
      )}
      <div className="account-seller-assisted-buying-settings-control__checkbox-row">
        <Field>
          <Checkbox
            name="allowRemoteShoppingAssistance"
            value="true"
            placeholder={checkboxLabel}
            label={checkboxLabel}
            checked={isRemoteShoppingAssistanceEnabled}
            onChange={(event: JSX.TargetedEvent<HTMLInputElement>) =>
              handleCheckboxChange(event.currentTarget.checked)
            }
          />
        </Field>
        {checkboxTooltip ? (
          <div className="account-seller-assisted-buying-settings-control__info-container">
            <button
              type="button"
              className="account-seller-assisted-buying-settings-control__info-icon"
              onMouseEnter={() => setShowTooltip(true)}
              onMouseLeave={() => setShowTooltip(false)}
              onFocusCapture={() => setShowTooltip(true)}
              onBlurCapture={() => setShowTooltip(false)}
              aria-label={checkboxTooltip}
            >
              ?
            </button>
            {showTooltip ? (
              <span
                className="account-seller-assisted-buying-settings-control__tooltip"
                role="tooltip"
              >
                {checkboxTooltip}
                <span className="account-seller-assisted-buying-settings-control__tooltip-arrow" />
              </span>
            ) : null}
          </div>
        ) : null}
      </div>
    </div>
  );
};
