import {
  deletePaymentToken,
  getCustomerPaymentTokens,
} from '@/account/api';
import { StoredPaymentMethodDisplay } from '@/account/data/models/stored-payment-method';
import { events } from '@adobe-commerce/event-bus';
import { useCallback, useEffect, useRef, useState } from 'preact/hooks';

/** @see `Events` augmentation in `src/types/events.d.ts` */
const customerPaymentTokensEvent = 'account/customerPaymentTokens';

/** Sentinel for `actionError` when delete succeeds at the transport layer but returns false. */
export const PAYMENT_METHOD_REMOVE_FAILED = '__REMOVE_FAILED__';

export const usePaymentMethods = (filterPaymentMethodCodes?: string[]) => {
  const itemsSourceRef = useRef<'event' | 'api'>('api');
  const prevFilterKeyRef = useRef<string | undefined>(undefined);

  const [items, setItems] = useState<StoredPaymentMethodDisplay[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [actionError, setActionError] = useState<string | null>(null);
  const [removingHash, setRemovingHash] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    setLoadError(null);
    setActionError(null);

    try {
      const next = await getCustomerPaymentTokens(filterPaymentMethodCodes);

      itemsSourceRef.current = 'api';
      setItems(next);
    } catch (e) {
      setItems([]);
      setLoadError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  }, [filterPaymentMethodCodes]);

  useEffect(() => {
    let cancelled = false;
    let consumedFromBus = false;

    const sub = events.on(
      customerPaymentTokensEvent,
      (payload) => {
        if (cancelled) return;
        consumedFromBus = true;
        itemsSourceRef.current = 'event';
        setItems(Array.isArray(payload) ? payload : []);
        setLoadError(null);
        setLoading(false);
      },
      { eager: true }
    );

    if (!sub || !consumedFromBus) {
      void load();
    }

    return () => {
      cancelled = true;
      sub?.off();
    };
  }, [load]);

  const filterKey = filterPaymentMethodCodes?.join(',') ?? '';

  useEffect(() => {
    if (itemsSourceRef.current !== 'api') return;

    if (prevFilterKeyRef.current === undefined) {
      prevFilterKeyRef.current = filterKey;
      return;
    }

    if (prevFilterKeyRef.current === filterKey) return;

    prevFilterKeyRef.current = filterKey;
    void load();
  }, [filterKey, load]);

  const removeToken = useCallback(async (publicHash: string) => {
    setActionError(null);
    setRemovingHash(publicHash);

    try {
      const ok = await deletePaymentToken(publicHash);

      if (ok) {
        setItems((prev) => prev.filter((t) => t.publicHash !== publicHash));
      } else {
        setActionError(PAYMENT_METHOD_REMOVE_FAILED);
      }
    } catch (e) {
      setActionError(e instanceof Error ? e.message : String(e));
    } finally {
      setRemovingHash(null);
    }
  }, []);

  const refetch = useCallback(async () => {
    if (itemsSourceRef.current === 'event') {
      const last = events.lastPayload(customerPaymentTokensEvent);

      if (last === undefined) return;

      setItems(Array.isArray(last) ? last : []);
      setLoadError(null);
      setActionError(null);
      return;
    }

    await load();
  }, [load]);

  return {
    items,
    loading,
    loadError,
    actionError,
    removingHash,
    removeToken,
    refetch,
  };
};
