import { classes, Container } from '@adobe-commerce/elsie/lib';
import { Header, InLineAlert } from '@adobe-commerce/elsie/components';
import { WarningWithCircle as ErrorIcon } from '@adobe-commerce/elsie/icons';
import { useText } from '@adobe-commerce/elsie/i18n';
import { useCallback, useState } from 'preact/hooks';
import { CardLoader, EmptyList, PaymentCard, PaymentModal } from '@/account/components';
import {
  PAYMENT_METHOD_REMOVE_FAILED,
  usePaymentMethods,
} from '@/account/hooks/containers/usePaymentMethods';
import type { StoredPaymentMethodDisplay } from '@/account/data/models';
import { PaymentMethodsWrapperProps } from '@/account/types';
import '@/account/components/PaymentMethodsWrapper/PaymentMethodsWrapper.css';

export const PaymentMethodsWrapper: Container<PaymentMethodsWrapperProps> = ({
  className,
  withHeader = true,
  minifiedView = false,
  filterPaymentMethodCodes,
}) => {
  const translations = useText({
    containerTitle: 'Account.Payments.containerTitle',
    loadError: 'Account.Payments.loadError',
    removeError: 'Account.Payments.removeError',
  });

  const {
    items,
    loading,
    loadError,
    actionError,
    removingHash,
    removeToken,
  } = usePaymentMethods(filterPaymentMethodCodes);

  const [pendingRemoval, setPendingRemoval] =
    useState<StoredPaymentMethodDisplay | null>(null);

  const closeRemovalModal = useCallback(() => {
    setPendingRemoval(null);
  }, []);

  const confirmRemoveToken = useCallback(async () => {
    if (!pendingRemoval) return;

    await removeToken(pendingRemoval.publicHash);
    setPendingRemoval(null);
  }, [pendingRemoval, removeToken]);

  const removeErrorMessage: string =
    actionError === PAYMENT_METHOD_REMOVE_FAILED ?
      translations.removeError
    : (actionError ?? '');

  const paymentMethodRows =
    items.length > 0 ?
      items.map((token) => {
        const { publicHash, ...paymentCardProps } = token;

        return (
          <PaymentCard
            key={publicHash}
            {...paymentCardProps}
            minifiedView={minifiedView}
            onRemove={
              removingHash !== null ?
                undefined
              : () => setPendingRemoval(token)
            }
          />
        );
      })
    : null;

  const emptyPaymentsView =
    items.length === 0 && !loadError ?
      <div
        className="account-payment-methods__empty"
        data-testid="paymentMethodsEmpty"
      >
        <EmptyList
          isEmpty
          typeList="payments"
          minifiedView={minifiedView}
        />
      </div>
    : null;

  return (
    <div
      className={classes(['account-payment-methods', className])}
      data-testid="paymentMethods"
    >
      {withHeader ? (
        <Header
          aria-label={translations.containerTitle}
          role="region"
          title={translations.containerTitle}
          divider={!minifiedView}
          className={minifiedView ? 'account-payment-methods-header' : ''}
        />
      ) : null}

      {loadError ? (
        <InLineAlert
          className="account-payment-methods__alert"
          type="error"
          variant="secondary"
          heading={translations.loadError}
          description={loadError}
          icon={<ErrorIcon />}
          data-testid="paymentMethodsLoadError"
        />
      ) : null}

      {actionError && !loadError ? (
        <InLineAlert
          className="account-payment-methods__alert"
          type="error"
          variant="secondary"
          heading={removeErrorMessage}
          icon={<ErrorIcon />}
          data-testid="paymentMethodsActionError"
        />
      ) : null}

      <PaymentModal
        open={pendingRemoval !== null}
        submitLoading={
          pendingRemoval !== null &&
          removingHash === pendingRemoval.publicHash
        }
        onRemoveToken={() => {
          void confirmRemoveToken();
        }}
        closeModal={closeRemovalModal}
        cardBrand={pendingRemoval?.cardBrand}
        lastFourDigits={pendingRemoval?.lastFourDigits}
        expired={pendingRemoval?.expired}
        variant={pendingRemoval?.variant}
        minifiedView={minifiedView}
      />

      {loading ? (
        <CardLoader testId="paymentMethodsLoader" />
      ) : (
        <div className="account-payment-methods__list">
          {paymentMethodRows ?? emptyPaymentsView}
        </div>
      )}
    </div>
  );
};
